#include <stdio.h>
int main() {
    int T, N, i, prev, curr;
    scanf("%d", &T);
    while (T--) {
        scanf("%d", &N);
        scanf("%d", &prev);
        long long total = prev;
        for (i = 1; i < N; i++) {
            scanf("%d", &curr);
            if (curr > prev) {
                total += curr - prev;
            }
            prev = curr;
        }
        printf("%lld\n", total);
    }
    return 0;
}

