code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long prev = sc.nextLong();
            long total = prev;
            for (int i = 1; i < N; i++) {
                long curr = sc.nextLong();
                if (curr > prev) {
                    total += curr - prev;
                }
                prev = curr;
            }
            System.out.println(total);
        }
    }
}

