const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];
const T = parseInt(readline());
for (let t = 0; t < T; t++) {
    const N = parseInt(readline());
    const measurements = readline().split(' ').map(x => parseInt(x));
    let total = measurements[0];
    let prev = measurements[0];
    for (let j = 1; j < N; j++) {
        const curr = measurements[j];
        if (curr > prev) {
            total += curr - prev;
        }
        prev = curr;
    }
    console.log(total);
}

